  ('pukao-6e11b43e-moex-00081', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-114-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '關於行政罰之管轄機關，下列敘述何者正確？', '["在中華民國領域外之中華民國船艦違反行政法上義務者，得由船艦出發地之主管機關管轄", "一行為違反同一行政法上義務，數機關均有管轄權而不能分別處理之先後者，由其共同上級機關指定之", "一行為違反數個行政法上義務而應處罰鍰，數機關均有管轄權者，由處理在先之機關管轄", "一行為違反數個行政法上義務而應受沒入或其他種類行政罰者，由各該主管機關分別裁處"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
