  ('pukao-6e11b43e-moex-00083', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-114-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '行政執行機關對義務人為拘提時，應踐行下列何種程序？', '["直接由行政執行官會同執行員當場緊急拘提之", "經通知警察機關後即可逕行拘提", "須向當地地方法院聲請裁定", "須向當地高等行政法院聲請裁定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00084', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-114-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '關於行政執行之代履行，下列敘述何者正確？', '["代履行與斷絕水電均為間接強制方法", "代履行僅適用於行為義務不履行之情形", "若對於代履行費用數額有爭執，應向民事法院提起訴訟", "應接受調查負說明義務而不履行者，不得採取代履行之行政執行方法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 34, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00085', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-114-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '甲因未履行行政法上義務，遭主管機關課處怠金，並限期履行。甲對此處置不服，依法聲明異議後，經主 管機關之上級機關決定維持原處置，甲應如何救濟？', '["應依訴願法就上級機關之決定提起訴願", "應就其所承受之不利益請求國家賠償", "應提起行政訴訟請求撤銷該處置", "應就此決定提起憲法訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00086', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-114-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '依政府資訊公開法規定，下列敘述何者錯誤？', '["有中華民國國籍而在國內無戶籍者，得申請提供政府資訊", "政府機關得主動公開，或依人民申請提供政府資訊", "應主動公開之政府資訊，政府機關未公開者，人民亦得申請提供", "申請提供之政府資訊，如已在網路公開者，得以告知申請人查詢方法以代提供"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00087', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-114-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '甲於申請期間內在郵局以掛號郵寄方式向主管機關申請補助，因山區道路坍方，郵件無法送出，逾期10日 始到達機關。下列敘述何者正確？', '["以主管機關收受申請之日為準，故申請已逾期", "以甲交郵當日之郵戳為準，故申請未逾期", "因非可歸責於甲之事由，甲得於道路修復後20日內，申請回復原狀", "因非可歸責於甲之事由，申請期限得延後至郵件到達後10日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00088', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-114-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '下列何者非屬正當行政程序之內涵？', '["公務員負有法定之迴避義務", "行政機關應依法提供相對人或利害關係人閱覽卷宗", "所有之行政決定均應讓相對人或利害關係人有陳述意見之機會", "行政處分之作成原則上應附具理由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL)
